# 解决 NumPy 类型不能序列化的问题

## 问题原因
JSON 不支持 NumPy 的数据类型（如 `float32`, `int64`, `ndarray` 等）

## 解决方案

### 方法1：转换为 Python 原生类型（推荐）
```python
import json
import numpy as np

data = {
    'value': np.float32(3.14),
    'array': np.array([1, 2, 3])
}

# 转换函数
def convert_to_python_type(obj):
    if isinstance(obj, np.ndarray):
        return obj.tolist()
    elif isinstance(obj, (np.float32, np.float64)):
        return float(obj)
    elif isinstance(obj, (np.int32, np.int64)):
        return int(obj)
    elif isinstance(obj, dict):
        return {k: convert_to_python_type(v) for k, v in obj.items()}
    elif isinstance(obj, list):
        return [convert_to_python_type(item) for item in obj]
    return obj

# 转换后保存
data_converted = convert_to_python_type(data)
with open('data.json', 'w', encoding='utf-8') as f:
    json.dump(data_converted, f, indent=4)
```

### 方法2：使用自定义 JSON Encoder
```python
import json
import numpy as np

class NumpyEncoder(json.JSONEncoder):
    def default(self, obj):
        if isinstance(obj, np.ndarray):
            return obj.tolist()
        if isinstance(obj, (np.float32, np.float64)):
            return float(obj)
        if isinstance(obj, (np.int32, np.int64)):
            return int(obj)
        if isinstance(obj, np.bool_):
            return bool(obj)
        return super().default(obj)

# 使用自定义 encoder
data = {
    'value': np.float32(3.14),
    'array': np.array([1, 2, 3])
}

with open('data.json', 'w', encoding='utf-8') as f:
    json.dump(data, f, cls=NumpyEncoder, indent=4)
```

### 方法3：手动转换字典
```python
import numpy as np
import json

data = {
    'loss': np.float32(0.5),
    'scores': np.array([0.8, 0.9, 0.95]),
    'count': np.int64(100)
}

# 手动转换
data_converted = {
    'loss': float(data['loss']),
    'scores': data['scores'].tolist(),
    'count': int(data['count'])
}

with open('data.json', 'w', encoding='utf-8') as f:
    json.dump(data_converted, f, indent=4)
```

### 方法4：使用 `default` 参数（简洁）
```python
import json
import numpy as np

def numpy_to_python(obj):
    if isinstance(obj, np.ndarray):
        return obj.tolist()
    if isinstance(obj, (np.float32, np.float64, np.float16)):
        return float(obj)
    if isinstance(obj, (np.int32, np.int64, np.int16, np.int8)):
        return int(obj)
    if isinstance(obj, np.bool_):
        return bool(obj)
    raise TypeError(f"Object of type {type(obj)} is not JSON serializable")

# 直接使用
data = {'value': np.float32(3.14)}

with open('data.json', 'w', encoding='utf-8') as f:
    json.dump(data, f, default=numpy_to_python, indent=4)
```

## 最简单的完整方案（推荐）
```python
import json
import numpy as np

class NumpyEncoder(json.JSONEncoder):
    def default(self, obj):
        if isinstance(obj, np.ndarray):
            return obj.tolist()
        if isinstance(obj, np.integer):
            return int(obj)
        if isinstance(obj, np.floating):
            return float(obj)
        if isinstance(obj, np.bool_):
            return bool(obj)
        return super().default(obj)

# 保存
with open('data.json', 'w', encoding='utf-8') as f:
    json.dump(data, f, cls=NumpyEncoder, indent=4, ensure_ascii=False)
```

**一行代码快速修复：**
```python
# 如果只是个别值
data['value'] = float(data['value'])  # 转换 float32 → float
data['array'] = data['array'].tolist()  # 转换 ndarray → list
```
